			"'use client'\n\nimport { parseDate, Time } from '@internationalized/date'\n\nimport { cn } from '../../registry/lib/utils'\nimport { Button } from '../../registry/ui/button'\nimport { Calendar } from '../../registry/ui/calendar'\nimport {\n  Card,\n  CardContent,\n  CardDescription,\n  CardFooter,\n  CardHeader,\n  CardTitle,\n} from '../../registry/ui/card'\nimport { Label } from '../../registry/ui/field'\nimport { DateInput } from '../../registry/ui/input'\nimport { TimeField } from '../../registry/ui/time-field'\n\nexport function Booking({ className, ...props }: React.ComponentProps<'div'>) {\n  return (\n    <Card className={cn('', className)} {...props}>\n      <CardHeader>\n        <CardTitle>Booking</CardTitle>\n        <CardDescription>Pick a time for your meeting.</CardDescription>\n      </CardHeader>\n      <CardContent className=\"space-y-3\">\n        <Calendar\n          className=\"w-full border-0 bg-transparent p-0\"\n          defaultValue={parseDate('2025-09-23')}\n        />\n        <div className=\"grid grid-cols-2 gap-2\">\n          <TimeField defaultValue={new Time(9, 0)}>\n            <Label>Start time</Label>\n            <DateInput />\n          </TimeField>\n          <TimeField defaultValue={new Time(9, 30)}>\n            <Label>End time</Label>\n            <DateInput />\n          </TimeField>\n        </div>\n      </CardContent>\n      <CardFooter className=\"justify-end gap-2\">\n        <Button>Dismiss</Button>\n        <Button variant=\"primary\">Apply</Button>\n      </CardFooter>\n    </Card>\n  )\n}\n",
