			"import type { RegistryItem } from '../../types'\n\nconst alertMeta = {\n  name: 'alert',\n  type: 'registry:ui',\n  group: 'feedback',\n  files: [\n    {\n      type: 'registry:ui',\n      path: 'ui/alert/base.tsx',\n      target: 'ui/alert.tsx',\n    },\n  ],\n  params: {\n    style: {\n      kind: 'enum',\n      default: 'default',\n      values: ['default', 'sousse'] as const,\n    },\n    radius: {\n      kind: 'scalar',\n      type: 'radius',\n      cssVar: '--alert-radius',\n      default: '--radius-lg',\n    },\n  },\n} satisfies RegistryItem\n\nexport default alertMeta\n",
