		target: "registry/ui/switch/meta.ts",
		content:
			"import type { RegistryItem } from '../../types'\n\nconst switchMeta = {\n  name: 'switch',\n  type: 'registry:ui',\n  group: 'selection-controls',\n  files: [\n    {\n      type: 'registry:ui',\n      path: 'ui/switch/base.tsx',\n      target: 'ui/switch.tsx',\n    },\n  ],\n  registryDependencies: ['focus-styles', 'field'],\n  params: {\n    radius: {\n      kind: 'scalar',\n      type: 'radius',\n      cssVar: '--switch-radius',\n      default: '--radius-full',\n    },\n    'card-radius': {\n      kind: 'scalar',\n      type: 'radius',\n      cssVar: '--switch-card-radius',\n      default: '--radius-lg',\n      description:\n        'Radius of the switch control when it contains label content.',\n    },\n  },\n} satisfies RegistryItem\n\nexport default switchMeta\n",
