			"@utility skeleton {\n  position: relative;\n  overflow: hidden;\n  background-color: var(--color-muted);\n  background-position: 100%;\n\n  &:where(img, video, canvas, svg) {\n    content-visibility: hidden;\n  }\n}\n\n@utility skeleton--shimmer {\n  &:where(.skeleton),\n  &\n    :where(\n      .skeleton,\n      [data-skeleton],\n      [data-text],\n      [data-label],\n      [data-description],\n      [data-card-title],\n      [data-card-description],\n      [data-menu-item-label],\n      [data-menu-item-description],\n      [data-listbox-item-label],\n      [data-listbox-item-description],\n      [data-button],\n      [data-input-control],\n      [data-badge],\n      [data-tag],\n      [data-kbd],\n      [data-combobox-value],\n      [data-avatar],\n      [data-avatar-group-count],\n      h1,\n      h2,\n      h3,\n      h4,\n      h5,\n      h6,\n      p,\n      small,\n      strong,\n      em,\n      code,\n      kbd,\n      samp,\n      figcaption,\n      legend\n    ) {\n    overflow: hidden;\n    background-image: linear-gradient(\n      to right,\n      var(--color-muted) 33%,\n      color-mix(in oklab, var(--color-muted), var(--color-bg) 45%),\n      var(--color-muted) 66%\n    );\n    background-size: 300% 100%;\n    background-position: 100%;\n    background-repeat: no-repeat;\n  }\n}\n\n@utility skeleton--pulse {\n  &:where(.skeleton),\n  &\n    :where(\n      .skeleton,\n      [data-skeleton],\n      [data-text],\n      [data-label],\n      [data-description],\n      [data-card-title],\n      [data-card-description],\n      [data-menu-item-label],\n      [data-menu-item-description],\n      [data-listbox-item-label],\n      [data-listbox-item-description],\n      [data-button],\n      [data-input-control],\n      [data-badge],\n      [data-tag],\n      [data-kbd],\n      [data-combobox-value],\n      [data-avatar],\n      [data-avatar-group-count],\n      h1,\n      h2,\n      h3,\n      h4,\n      h5,\n      h6,\n      p,\n      small,\n      strong,\n      em,\n      code,\n      kbd,\n      samp,\n      figcaption,\n      legend\n    ) {\n    opacity: 1;\n  }\n}\n\n@utility skeleton--none {\n  &:where(.skeleton),\n  &\n    :where(\n      .skeleton,\n      [data-skeleton],\n      [data-text],\n      [data-label],\n      [data-description],\n      [data-card-title],\n      [data-card-description],\n      [data-menu-item-label],\n      [data-menu-item-description],\n      [data-listbox-item-label],\n      [data-listbox-item-description],\n      [data-button],\n      [data-input-control],\n      [data-badge],\n      [data-tag],\n      [data-kbd],\n      [data-combobox-value],\n      [data-avatar],\n      [data-avatar-group-count],\n      h1,\n      h2,\n      h3,\n      h4,\n      h5,\n      h6,\n      p,\n      small,\n      strong,\n      em,\n      code,\n      kbd,\n      samp,\n      figcaption,\n      legend\n    ) {\n    background-image: none;\n    animation: none;\n  }\n}\n",
